import{_ as e,o as s,c as a,a2 as i}from"./chunks/framework.DGp-bpT-.js";const g=JSON.parse('{"title":"Compliance & Security Controls","description":"","frontmatter":{},"headers":[],"relativePath":"guide/compliance.md","filePath":"guide/compliance.md"}'),n={name:"guide/compliance.md"};function r(o,t,l,d,c,p){return s(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="compliance-security-controls" tabindex="-1">Compliance &amp; Security Controls <a class="header-anchor" href="#compliance-security-controls" aria-label="Permalink to &quot;Compliance &amp; Security Controls&quot;">​</a></h1><p>Docker Secret Operator (DSO) is built to help organizations achieve and maintain rigorous compliance standards. While no single software guarantees compliance, DSO&#39;s architecture satisfies many critical requirements out-of-the-box.</p><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p>This guide is a readiness resource showing how DSO maps to common frameworks. It does not replace a formal compliance audit from a certified assessor.</p></div><h2 id="conceptual-framework" tabindex="-1">Conceptual Framework <a class="header-anchor" href="#conceptual-framework" aria-label="Permalink to &quot;Conceptual Framework&quot;">​</a></h2><p>DSO operates on three compliance pillars:</p><ol><li><strong>Zero Disk Persistence:</strong> Secrets exist exclusively in memory (tmpfs/RAM).</li><li><strong>Machine Identity:</strong> Role-based access without static credentials.</li><li><strong>Immutable Audit Trails:</strong> Every lifecycle event is logged.</li></ol><h2 id="soc-2-type-ii-mappings" tabindex="-1">SOC 2 Type II Mappings <a class="header-anchor" href="#soc-2-type-ii-mappings" aria-label="Permalink to &quot;SOC 2 Type II Mappings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Trust Services Criteria</th><th>DSO Control Implementation</th></tr></thead><tbody><tr><td><strong>CC6.1 (Logical Access)</strong></td><td>Credentials (e.g. <code>VAULT_TOKEN</code>) are dynamically retrieved and auto-renewed. No passwords exist in code or config files.</td></tr><tr><td><strong>CC6.2 (User Access)</strong></td><td>DSO integrates natively into IAM platforms (AWS Instance Profiles, Azure Managed Identity), ensuring secrets are tied to the compute resource, not an interactive user.</td></tr><tr><td><strong>CC7.1 (System Configuration)</strong></td><td>All mappings and injection policies are declared as code in <code>dso.yaml</code> and verified by JSON Schema before deployment.</td></tr><tr><td><strong>CC7.2 (Security Events)</strong></td><td>The structured JSON audit log emits standardized <code>audit</code> events required for SIEM ingestion when rotations, fetches, or injections occur.</td></tr><tr><td><strong>CC8.1 (Change Management)</strong></td><td>Secret rotation is fully automated via the Strategy engine, meaning developers do not need shell access to servers to update passwords safely.</td></tr></tbody></table><h2 id="iso-27001-mappings" tabindex="-1">ISO 27001 Mappings <a class="header-anchor" href="#iso-27001-mappings" aria-label="Permalink to &quot;ISO 27001 Mappings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Annex A Control</th><th>DSO Mitigation Strategy</th></tr></thead><tbody><tr><td><strong>A.9.2.3 (Management of secret auth info)</strong></td><td>Secret data is transported via local Unix domain socket isolated to root/docker groups. It bypasses the network stack.</td></tr><tr><td><strong>A.12.3.1 (Information Backup)</strong></td><td>DSO is completely stateless. The authoritative source of truth remains HashiCorp Vault, AWS, or Azure. If a node fails, secrets are automatically re-fetched.</td></tr><tr><td><strong>A.12.4.1 (Event Logging)</strong></td><td>Administrator acts, system faults, auth failures are recorded to <code>stdout</code>/journald which forwards natively to aggregator daemons.</td></tr><tr><td><strong>A.14.2.5 (Secure System Engineering)</strong></td><td>Components are sandboxed. The provider plugins communicate via strictly typed RPC, limiting blast radius if an individual provider is compromised.</td></tr></tbody></table><h2 id="pci-dss-readiness" tabindex="-1">PCI-DSS Readiness <a class="header-anchor" href="#pci-dss-readiness" aria-label="Permalink to &quot;PCI-DSS Readiness&quot;">​</a></h2><p>For organizations subject to Cardholder Data Environment (CDE) rules:</p><ul><li><strong>Requirement 3.2.1:</strong> Cardholder authentication secrets are never written to <code>docker inspect</code> outputs or image layers.</li><li><strong>Requirement 8.2.1:</strong> Cryptographic secrets and tokens are rotated automatically per your internal policy defined in <code>dso.yaml</code> (<code>watch.interval</code>).</li><li><strong>Requirement 10.2.1:</strong> All requests to the underlying Cloud Secrets Manager include the specific IAM context for auditing at the network edge.</li></ul><h2 id="audit-subsystem-export" tabindex="-1">Audit Subsystem Export <a class="header-anchor" href="#audit-subsystem-export" aria-label="Permalink to &quot;Audit Subsystem Export&quot;">​</a></h2><p>To guarantee compliance, make sure you configure your Docker host&#39;s logging drivers to forward standard output towards a centralized aggregation server that guarantees WORM (Write Once Read Many) immutability.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Example docker-compose configuration for compliant logging</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  myapp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">myapp:prod</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    logging</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      driver</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;awslogs&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      options</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        awslogs-region</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;us-east-1&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        awslogs-group</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dso-audit-events&quot;</span></span></code></pre></div>`,16)])])}const u=e(n,[["render",r]]);export{g as __pageData,u as default};
